import SweetAlertContext from './SweetAlertContext'
import React,{useState} from 'react'
import Swal from "sweetalert2";


function SweetAlertState(props) {
    const successAlert = () => {
        Swal.fire({
          title: "Good job!",
          text: "You clicked the button",
          icon: "success"
        });
        // or Swal.fire( 'Good job!','You clicked the button','success');
      };
      const questionAlert = () => {
        Swal.fire({  
            title: 'Error',  
            text: 'Invalid Credentials !! Please Try Again',
            icon: 'error'
          }); 
    }
    const Address = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Address Saved Successfully',
            icon: 'success'
          }); 
    }
    const Delete = () => {
        Swal.fire({  
            title: 'Great !',  
            text: 'Deleted Successfully',
            icon: 'success'
          }); 
    }
    return (
        <SweetAlertContext.Provider value={{successAlert,questionAlert,Address}}>
            {props.children};
        </SweetAlertContext.Provider>
    )
}

export default SweetAlertState
